
#!/usr/bin/env python3
import base64

def xor_decrypt(text, key):
    decrypted = []
    key_length = len(key)
    for i, char in enumerate(text):
        key_char = key[i % key_length]
        decrypted_char = chr(ord(char) ^ ord(key_char))
        decrypted.append(decrypted_char)
    return ''.join(decrypted)

# البيانات المشفرة
encrypted_data = """"""

def decrypt_with_password(password):
    data = encrypted_data
    layers = 1
    
    for i in range(layers-1, -1, -1):
        data = base64.b64decode(data).decode()
        layer_key = password + str(i) + "joker_salt"
        data = xor_decrypt(data, layer_key)
    
    return data

if __name__ == "__main__":
    password = input("🔐 أدخل كلمة السر: ")
    try:
        decrypted = decrypt_with_password(password)
        exec(decrypted)
    except:
        print("❌ كلمة السر خاطئة أو البيانات تالفة!")
